async function execute(browser, params) {
    const cartItem = await browser.extractComponent(
        {
            typeName: 'CartItem',
            schema: '{ name: string; removeButtonSelector: string; }'
        },
        params.productName
    );
    if (!cartItem || !cartItem.removeButtonSelector) {
        throw new Error('Could not find product "' + params.productName + '" in the cart');
    }
    await browser.click(cartItem.removeButtonSelector);
    await browser.awaitPageInteraction();
    return { success: true, message: 'Removed ' + params.productName + ' from cart' };
}
